          </div>
          </TabsContent>

          {/* SCROLLABLE BODY - Shipment Tab */}
          <TabsContent value="shipment" className="flex-1 overflow-y-auto px-4 py-3 space-y-4 mt-0">
            {/* Tracking Details */}
