                    ? [
                        orderDetails.shippingAddressLine1,
                        orderDetails.shippingAddressLine2,
                        orderDetails.shippingCity,
                        orderDetails.shippingState,
                        orderDetails.shippingPincode,
                        orderDetails.shippingCountry
