              </div>
              <p className="text-sm text-muted-foreground" data-testid="text-profile-email">
                {form.watch("email")}
              </p>
              {user?.employeeId && (
                <p className="text-xs text-muted-foreground" data-testid="text-employee-id">
                  Employee ID: {user.employeeId}
