client/src/components/settings-attendanc.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { Clock, LogIn, LogOut, Calendar } from "lucide-react";
import { format } from "date-fns";
import type { Attendance } from "@shared/schema";

interface AttendanceProps {
  userRole: "admin" | "manager" | "agent";
}

export function AttendanceSettings({ userRole }: AttendanceProps) {
  const { toast } = useToast();
  const userId = localStorage.getItem("userId") || "";

  // Fetch today's attendance
  const { data: todayAttendance, isLoading: attendanceLoading } = useQuery<Attendance>({
    queryKey: ["/api/attendance/today", userId],
    enabled: !!userId,
  });

  // Fetch attendance history (last 30 days)
  const thirtyDaysAgo = new Date();
  thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

  const { data: attendanceHistory, isLoading: historyLoading } = useQuery<Attendance[]>({
    queryKey: ["/api/attendance/records", { 
      userId, 
      startDate: thirtyDaysAgo.toISOString() 
    }],
    enabled: !!userId,
  });

  // Clock In Mutation
  const clockInMutation = useMutation({
    mutationFn: async () => {
      return await apiRequest("POST", "/api/attendance/clock-in", { userId });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/attendance/today"] });
      queryClient.invalidateQueries({ queryKey: ["/api/attendance/records"] });
      queryClient.invalidateQueries({ queryKey: ["/api/attendance/team-today"] });
      toast({
        title: "Clocked In",
        description: "Your attendance has been recorded.",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Clock In Failed",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  // Clock Out Mutation
  const clockOutMutation = useMutation({
    mutationFn: async () => {
      return await apiRequest("POST", "/api/attendance/clock-out", { userId });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/attendance/today"] });
      queryClient.invalidateQueries({ queryKey: ["/api/attendance/records"] });
      queryClient.invalidateQueries({ queryKey: ["/api/attendance/team-today"] });
      toast({
        title: "Clocked Out",
        description: "Your work hours have been recorded.",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Clock Out Failed",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const isClockedIn = todayAttendance?.clockInTime && !todayAttendance?.clockOutTime;
  const isClockedOut = todayAttendance?.clockInTime && todayAttendance?.clockOutTime;

  const handleClockIn = () => {
    clockInMutation.mutate();
  };

  const handleClockOut = () => {
    clockOutMutation.mutate();
  };

  return (
    <div className="space-y-6">
      {/* Clock In/Out Card */}
      <Card data-testid="card-clock-inout">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Clock className="h-5 w-5" />
            Clock In / Clock Out
          </CardTitle>
          <CardDescription>
            Track your work hours for HR and payroll purposes. This does not affect your ability to receive order assignments.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {attendanceLoading ? (
            <div className="space-y-2">
              <Skeleton className="h-20 w-full" />
            </div>
          ) : (
            <>
              {/* Today's Status */}
              <div className="flex items-center justify-between p-4 border rounded-md">
                <div className="space-y-1">
                  <p className="text-sm font-medium">Today's Status</p>
                  <p className="text-xs text-muted-foreground">{format(new Date(), "EEEE, MMMM d, yyyy")}</p>
                </div>
                <div className="flex items-center gap-2">
                  {!todayAttendance?.clockInTime ? (
                    <Badge variant="outline" data-testid="badge-status-not-clocked">Not Clocked In</Badge>
                  ) : isClockedOut ? (
                    <Badge variant="secondary" data-testid="badge-status-completed">Completed</Badge>
                  ) : (
                    <Badge className="bg-green-500 text-white" data-testid="badge-status-working">Working</Badge>
                  )}
                </div>
              </div>

              {/* Clock In/Out Times */}
              {todayAttendance?.clockInTime && (
                <div className="grid grid-cols-2 gap-4">
                  <div className="p-3 border rounded-md">
                    <p className="text-xs text-muted-foreground mb-1">Clock In Time</p>
                    <p className="text-sm font-medium" data-testid="text-clock-in-time">
                      {format(new Date(todayAttendance.clockInTime), "h:mm a")}
                    </p>
                  </div>
                  {todayAttendance.clockOutTime && (
                    <div className="p-3 border rounded-md">
                      <p className="text-xs text-muted-foreground mb-1">Clock Out Time</p>
                      <p className="text-sm font-medium" data-testid="text-clock-out-time">
                        {format(new Date(todayAttendance.clockOutTime), "h:mm a")}
                      </p>
                    </div>
                  )}
                </div>
              )}

              {todayAttendance?.totalHours && (
                <div className="p-3 border rounded-md">
                  <p className="text-xs text-muted-foreground mb-1">Total Hours Worked</p>
                  <p className="text-sm font-medium" data-testid="text-total-hours">
                    {parseFloat(todayAttendance.totalHours).toFixed(2)} hours
                  </p>
                </div>
              )}

              {/* Action Buttons */}
              <div className="flex gap-2">
                {!isClockedIn && !isClockedOut && (
                  <Button
                    onClick={handleClockIn}
                    disabled={clockInMutation.isPending}
                    className="flex-1"
                    data-testid="button-clock-in"
                  >
                    <LogIn className="mr-2 h-4 w-4" />
                    {clockInMutation.isPending ? "Clocking In..." : "Clock In"}
                  </Button>
                )}
                {isClockedIn && (
                  <Button
                    onClick={handleClockOut}
                    disabled={clockOutMutation.isPending}
                    variant="outline"
                    className="flex-1"
                    data-testid="button-clock-out"
                  >
                    <LogOut className="mr-2 h-4 w-4" />
                    {clockOutMutation.isPending ? "Clocking Out..." : "Clock Out"}
                  </Button>
                )}
                {isClockedOut && (
                  <div className="flex-1 text-center text-sm text-muted-foreground py-2">
                    You have completed your shift for today
                  </div>
                )}
              </div>
            </>
          )}
        </CardContent>
      </Card>

      {/* Attendance History */}
      <Card data-testid="card-attendance-history">
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <Calendar className="h-5 w-5" />
            Attendance History
          </CardTitle>
          <CardDescription>
            Your attendance records for the last 30 days
          </CardDescription>
        </CardHeader>
        <CardContent>
          {historyLoading ? (
            <div className="space-y-2">
              <Skeleton className="h-12 w-full" />
              <Skeleton className="h-12 w-full" />
              <Skeleton className="h-12 w-full" />
            </div>
          ) : !attendanceHistory || attendanceHistory.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground" data-testid="text-no-history">
              <Calendar className="h-12 w-12 mx-auto mb-2 opacity-50" />
              <p>No attendance records found</p>
            </div>
          ) : (
            <div className="space-y-2">
              {attendanceHistory.map((record) => (
                <div
                  key={record.id}
                  className="flex items-center justify-between p-3 border rounded-md"
                  data-testid={`attendance-record-${record.id}`}
                >
                  <div className="flex-1">
                    <p className="text-sm font-medium">
                      {format(new Date(record.date), "EEEE, MMMM d, yyyy")}
                    </p>
                    <div className="flex gap-4 mt-1">
                      {record.clockInTime && (
                        <p className="text-xs text-muted-foreground">
                          In: {format(new Date(record.clockInTime), "h:mm a")}
                        </p>
                      )}
                      {record.clockOutTime && (
                        <p className="text-xs text-muted-foreground">
                          Out: {format(new Date(record.clockOutTime), "h:mm a")}
                        </p>
                      )}
                    </div>
                  </div>
                  <div className="text-right">
                    {record.totalHours ? (
                      <Badge variant="secondary">
                        {parseFloat(record.totalHours).toFixed(2)} hrs
                      </Badge>
                    ) : (
                      <Badge variant="outline">Incomplete</Badge>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

client/src/components/team-presence.tsx.content:
import { useQuery, useMutation } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { Users, UserCheck, UserX, Package, Clock } from "lucide-react";
import type { User, Order as BackendOrder, Attendance } from "@shared/schema";

interface TeamPresenceProps {
  userRole: "admin" | "manager" | "agent";
}

export function TeamPresence({ userRole }: TeamPresenceProps) {
  const { toast } = useToast();

  // Fetch team members
  const { data: users, isLoading: usersLoading } = useQuery<User[]>({
    queryKey: ["/api/users"],
  });

  // Fetch orders to calculate workload
  const { data: ordersResponse, isLoading: ordersLoading } = useQuery<{ orders: BackendOrder[]; total: number }>({
    queryKey: ["/api/orders"],
  });

  // Fetch today's attendance for all team members
  const { data: teamAttendance, isLoading: attendanceLoading } = useQuery<Attendance[]>({
    queryKey: ["/api/attendance/team-today"],
  });

  // Create a map of userId -> attendance record for quick lookup
  const attendanceMap = new Map<string, Attendance>();
  teamAttendance?.forEach((record) => {
    attendanceMap.set(record.userId, record);
  });

  // Calculate workload for each user
  const workloadMap = new Map<string, number>();
  ordersResponse?.orders?.forEach((order) => {
    if (order.assignedTo && order.status !== "delivered" && order.status !== "cancelled") {
      const current = workloadMap.get(order.assignedTo) || 0;
      workloadMap.set(order.assignedTo, current + 1);
    }
  });

  // Update presence status mutation
  const updatePresenceMutation = useMutation({
    mutationFn: async ({ userId, status }: { userId: string; status: "present" | "onleave" | "inactive" }) => {
      return await apiRequest("POST", "/api/users/presence", { userId, status });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/users"] });
      toast({
        title: "Status Updated",
        description: "Team member account status has been updated.",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Update Failed",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const handlePresenceChange = (userId: string, status: "present" | "onleave" | "inactive") => {
    updatePresenceMutation.mutate({ userId, status });
  };

  const getRoleBadge = (role: string) => {
    switch (role) {
      case "admin":
        return <Badge variant="default">Admin</Badge>;
      case "manager":
        return <Badge variant="secondary">Manager</Badge>;
      case "agent":
        return <Badge variant="outline">Agent</Badge>;
      default:
        return <Badge variant="outline">{role}</Badge>;
    }
  };

  const isLoading = usersLoading || ordersLoading || attendanceLoading;

  // Filter to agents and managers only
  const teamMembers = users?.filter((u) => u.role === "agent" || u.role === "manager") || [];

  // Helper to derive live status from attendance record
  const getLiveStatus = (userId: string, accountStatus: string): "online" | "break" | "offline" => {
    if (accountStatus === "onleave" || accountStatus === "inactive") {
      return "offline";
    }
    const attendance = attendanceMap.get(userId);
    if (!attendance) return "offline";
    if (attendance.clockOutTime) return "offline";
    if (attendance.status === "break") return "break";
    return "online";
  };

  // Stats - count based on LIVE attendance status
  const onlineCount = teamMembers.filter((u) => getLiveStatus(u.id, u.presenceStatus || "inactive") === "online").length;
  const onBreakCount = teamMembers.filter((u) => getLiveStatus(u.id, u.presenceStatus || "inactive") === "break").length;
  const offlineCount = teamMembers.filter((u) => getLiveStatus(u.id, u.presenceStatus || "inactive") === "offline").length;
  const totalWorkload = Array.from(workloadMap.values()).reduce((sum, count) => sum + count, 0);

  // Only allow admins to manage presence
  const canManagePresence = userRole === "admin";

  return (
    <div className="space-y-6">
      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card data-testid="card-total-members">
          <CardHeader className="flex flex-row items-center justify-between gap-1 space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total Members</CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            {isLoading ? (
              <Skeleton className="h-8 w-16" />
            ) : (
              <div className="text-2xl font-bold">{teamMembers.length}</div>
            )}
          </CardContent>
        </Card>

        <Card data-testid="card-online-members">
          <CardHeader className="flex flex-row items-center justify-between gap-1 space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Online</CardTitle>
            <UserCheck className="h-4 w-4 text-green-500" />
          </CardHeader>
          <CardContent>
            {isLoading ? (
              <Skeleton className="h-8 w-16" />
            ) : (
              <div className="text-2xl font-bold text-green-500">{onlineCount}</div>
            )}
          </CardContent>
        </Card>

        <Card data-testid="card-break-members">
          <CardHeader className="flex flex-row items-center justify-between gap-1 space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">On Break</CardTitle>
            <Clock className="h-4 w-4 text-orange-500" />
          </CardHeader>
          <CardContent>
            {isLoading ? (
              <Skeleton className="h-8 w-16" />
            ) : (
              <div className="text-2xl font-bold text-orange-500">{onBreakCount}</div>
            )}
          </CardContent>
        </Card>

        <Card data-testid="card-total-workload">
          <CardHeader className="flex flex-row items-center justify-between gap-1 space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Active Orders</CardTitle>
            <Package className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            {isLoading ? (
              <Skeleton className="h-8 w-16" />
            ) : (
              <div className="text-2xl font-bold">{totalWorkload}</div>
            )}
          </CardContent>
        </Card>
      </div>

      {/* Team Members Table */}
      <Card data-testid="card-team-members">
        <CardHeader>
          <CardTitle>Team Status & Workload</CardTitle>
          <CardDescription>
            {canManagePresence 
              ? "Manage account status and view current workload for each team member"
              : "View team account status and current workload distribution"
            }
          </CardDescription>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="space-y-4">
              <Skeleton className="h-20 w-full" />
              <Skeleton className="h-20 w-full" />
              <Skeleton className="h-20 w-full" />
            </div>
          ) : teamMembers.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground" data-testid="text-no-members">
              <Users className="h-12 w-12 mx-auto mb-2 opacity-50" />
              <p>No team members found</p>
            </div>
          ) : (
            <div className="space-y-4">
              {teamMembers.map((member) => {
                const workload = workloadMap.get(member.id) || 0;
                const accountStatus = member.presenceStatus || "inactive";
                const liveStatus = getLiveStatus(member.id, accountStatus);

                return (
                  <div
                    key={member.id}
                    className="flex items-center justify-between p-4 border rounded-md"
                    data-testid={`member-${member.id}`}
                  >
                    <div className="flex-1 space-y-1">
                      <div className="flex items-center gap-2">
                        <p className="font-medium">{member.fullName}</p>
                        {getRoleBadge(member.role)}
                      </div>
                      <p className="text-sm text-muted-foreground">{member.email}</p>
                    </div>

                    <div className="flex items-center gap-4">
                      {/* Workload */}
                      <div className="text-center">
                        <p className="text-xs text-muted-foreground mb-1">Active Orders</p>
                        <div className="flex items-center gap-1">
                          <Package className="h-3 w-3" />
                          <span className="font-medium" data-testid={`workload-${member.id}`}>
                            {workload}
                          </span>
                        </div>
                      </div>

                      {/* Live Status - derived from attendance */}
                      <div className="w-24 text-center">
                        <p className="text-xs text-muted-foreground mb-1">Live Status</p>
                        <div data-testid={`live-status-${member.id}`}>
                          {liveStatus === "online" && (
                            <Badge className="bg-green-500 text-white">Online</Badge>
                          )}
                          {liveStatus === "break" && (
                            <Badge className="bg-orange-500 text-white">On Break</Badge>
                          )}
                          {liveStatus === "offline" && (
                            <Badge variant="secondary">Offline</Badge>
                          )}
                        </div>
                      </div>

                      {/* Account Status (admin can change) */}
                      <div className="w-40">
                        <p className="text-xs text-muted-foreground mb-1">Account Status</p>
                        {canManagePresence ? (
                          <Select
                            value={accountStatus}
                            onValueChange={(value) => handlePresenceChange(member.id, value as "present" | "onleave" | "inactive")}
                            disabled={updatePresenceMutation.isPending}
                          >
                            <SelectTrigger data-testid={`select-status-${member.id}`}>
                              <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                              <SelectItem value="present">Active</SelectItem>
                              <SelectItem value="onleave">On Leave</SelectItem>
                              <SelectItem value="inactive">Inactive</SelectItem>
                            </SelectContent>
                          </Select>
                        ) : (
                          <div data-testid={`status-display-${member.id}`}>
                            {accountStatus === "present" && (
                              <Badge className="bg-green-500/20 text-green-600 dark:text-green-400 border-green-500/30">Active</Badge>
                            )}
                            {accountStatus === "onleave" && (
                              <Badge variant="outline">On Leave</Badge>
                            )}
                            {accountStatus === "inactive" && (
                              <Badge variant="secondary">Inactive</Badge>
                            )}
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

