import { useState } from "react";
import { Button } from "@/components/ui/button";
import { CheckCircle2, XCircle, Clock, Loader2, ChevronDown } from "lucide-react";
import { CancelOrderModal } from "@/components/cancel-order-modal";
import { FollowupOrderModal } from "@/components/followup-order-modal";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";

interface CallStatusActionsProps {
  orderId: string;
  orderNumber: string;
  currentStatus?: "Pending" | "Confirmed" | "Cancelled" | "Follow Up";
  onConfirm: (orderId: string, notes?: string) => Promise<void>;
  onCancel: (orderId: string, reason: string, notes?: string) => Promise<void>;
  onFollowup: (orderId: string, followupAt: Date, notes?: string) => Promise<void>;
  disabled?: boolean;
}

export function CallStatusActions({
  orderId,
  orderNumber,
  currentStatus,
  onConfirm,
  onCancel,
  onFollowup,
  disabled = false,
}: CallStatusActionsProps) {
  const [cancelModalOpen, setCancelModalOpen] = useState(false);
  const [followupModalOpen, setFollowupModalOpen] = useState(false);
  const [confirmDialogOpen, setConfirmDialogOpen] = useState(false);
  const [confirmNotes, setConfirmNotes] = useState("");
  const [isConfirming, setIsConfirming] = useState(false);

  const handleConfirmClick = () => {
    setConfirmDialogOpen(true);
  };

  const handleConfirmOrder = async () => {
    try {
      setIsConfirming(true);
      await onConfirm(orderId, confirmNotes);
      setConfirmDialogOpen(false);
      setConfirmNotes("");
    } catch (error) {
      console.error("Error confirming order:", error);
    } finally {
      setIsConfirming(false);
    }
  };

  const handleCancelClick = () => {
    setCancelModalOpen(true);
  };

  const handleCancelOrder = async (reason: string, notes?: string) => {
    await onCancel(orderId, reason, notes);
  };

  const handleFollowupClick = () => {
    setFollowupModalOpen(true);
  };

  const handleScheduleFollowup = async (followupAt: Date, notes?: string) => {
    await onFollowup(orderId, followupAt, notes);
  };

  const getStatusColor = (status?: string) => {
    switch (status) {
      case "Confirmed":
        return "text-green-600 dark:text-green-400";
      case "Cancelled":
        return "text-red-600 dark:text-red-400";
      case "Follow Up":
        return "text-yellow-600 dark:text-yellow-400";
      default:
        return "text-purple-600 dark:text-purple-400";
    }
  };

  const getStatusIcon = (status?: string) => {
    switch (status) {
      case "Confirmed":
        return <CheckCircle2 className="h-4 w-4 mr-1" />;
      case "Cancelled":
        return <XCircle className="h-4 w-4 mr-1" />;
      case "Follow Up":
        return <Clock className="h-4 w-4 mr-1" />;
      default:
        return <Clock className="h-4 w-4 mr-1" />;
    }
  };

  if (currentStatus === "Confirmed" || currentStatus === "Cancelled") {
    // Show status badge for completed states
    return (
      <Button
        variant="outline"
        size="sm"
        disabled
        className={`${getStatusColor(currentStatus)} border-current`}
        data-testid={`button-status-${currentStatus.toLowerCase()}`}
      >
        {currentStatus === "Confirmed" ? (
          <CheckCircle2 className="h-4 w-4 mr-1" />
        ) : (
          <XCircle className="h-4 w-4 mr-1" />
        )}
        {currentStatus}
      </Button>
    );
  }

  return (
    <>
      <DropdownMenu>
        <DropdownMenuTrigger asChild>
          <Button
            variant="outline"
            size="sm"
            disabled={disabled}
            className={`gap-1 ${getStatusColor(currentStatus)}`}
            data-testid="dropdown-call-status"
          >
            {getStatusIcon(currentStatus)}
            {currentStatus || "Pending"}
            <ChevronDown className="h-3 w-3 ml-1" />
          </Button>
        </DropdownMenuTrigger>
        <DropdownMenuContent align="end" className="w-40">
          <DropdownMenuItem
            onClick={handleConfirmClick}
            className="gap-2 text-green-600 dark:text-green-400 focus:text-green-600 dark:focus:text-green-400"
            data-testid="menuitem-confirm"
          >
            <CheckCircle2 className="h-4 w-4" />
            Confirm
          </DropdownMenuItem>
          <DropdownMenuItem
            onClick={handleCancelClick}
            className="gap-2 text-red-600 dark:text-red-400 focus:text-red-600 dark:focus:text-red-400"
            data-testid="menuitem-cancel"
          >
            <XCircle className="h-4 w-4" />
            Cancel
          </DropdownMenuItem>
          <DropdownMenuItem
            onClick={handleFollowupClick}
            className="gap-2 text-yellow-600 dark:text-yellow-400 focus:text-yellow-600 dark:focus:text-yellow-400"
            data-testid="menuitem-followup"
          >
            <Clock className="h-4 w-4" />
            Follow-Up
          </DropdownMenuItem>
        </DropdownMenuContent>
      </DropdownMenu>

      {/* Confirm Dialog */}
      <AlertDialog open={confirmDialogOpen} onOpenChange={setConfirmDialogOpen}>
        <AlertDialogContent data-testid="dialog-confirm-order">
          <AlertDialogHeader>
            <AlertDialogTitle>Confirm Order</AlertDialogTitle>
            <AlertDialogDescription>
              Order {orderNumber} - Mark this order as confirmed and move it to Fulfil section?
            </AlertDialogDescription>
          </AlertDialogHeader>
          <div className="py-2">
            <Label htmlFor="confirm-notes">Notes (Optional)</Label>
            <Input
              id="confirm-notes"
              value={confirmNotes}
              onChange={(e) => setConfirmNotes(e.target.value)}
              placeholder="Add any notes..."
              className="mt-1.5"
              data-testid="input-confirm-notes"
            />
          </div>
          <AlertDialogFooter>
            <AlertDialogCancel
              disabled={isConfirming}
              data-testid="button-cancel-dialog"
            >
              Cancel
            </AlertDialogCancel>
            <AlertDialogAction
              onClick={handleConfirmOrder}
              disabled={isConfirming}
              data-testid="button-confirm-order"
            >
              {isConfirming && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
              Confirm Order
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Cancel Modal */}
      <CancelOrderModal
        open={cancelModalOpen}
        onOpenChange={setCancelModalOpen}
        onConfirm={handleCancelOrder}
        orderNumber={orderNumber}
      />

      {/* Follow-up Modal */}
      <FollowupOrderModal
        open={followupModalOpen}
        onOpenChange={setFollowupModalOpen}
        onConfirm={handleScheduleFollowup}
        orderNumber={orderNumber}
      />
    </>
  );
}

client/src/pages/fulfil.tsx.content:
import { useState } from "react";
import { useQuery } from "@tanstack/react-query";
import { format } from "date-fns";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Card, CardContent } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { Package, PackageCheck, ChevronLeft, ChevronRight } from "lucide-react";
import { OrderQuickPreview } from "@/components/order-quick-preview";
import { CourierSelectionModal } from "@/components/courier-selection-modal";
import { PageLayout } from "@/components/page-layout";
import { FulfilFilter } from "@/components/fulfil-filter";
import { PaymentBadge } from "@/components/payment-badge";
import type { Order as BackendOrder } from "@shared/schema";
import type { Order } from "@/components/orders-table";

export default function FulfilPage() {
  const [selectedOrders, setSelectedOrders] = useState<Set<string>>(new Set());
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);
  const [selectedOrderIndex, setSelectedOrderIndex] = useState<number>(-1);
  const [isQuickPreviewOpen, setIsQuickPreviewOpen] = useState(false);
  const [courierSelectionModalOpen, setCourierSelectionModalOpen] = useState(false);
  const [selectedOrderForCourier, setSelectedOrderForCourier] = useState<BackendOrder | null>(null);
  const [searchQuery, setSearchQuery] = useState("");
  const [dateRange, setDateRange] = useState<{ from?: Date; to?: Date }>({});
  const [paymentFilter, setPaymentFilter] = useState<string>("all");
  const [agentFilter, setAgentFilter] = useState<string>("all");
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState(50);

  // Fetch confirmed orders with server-side filtering
  const { data: ordersResponse, isLoading } = useQuery<{ orders: BackendOrder[]; total: number }>({
    queryKey: ["/api/orders", "Confirmed", currentPage, pageSize, agentFilter],
    queryFn: async () => {
      const params = new URLSearchParams({
        page: currentPage.toString(),
        limit: pageSize.toString(),
        callStatus: "Confirmed",
      });

      // Add agent filter if set
      if (agentFilter !== "all") {
        params.append("agentId", agentFilter);
      }

      const res = await fetch(`/api/orders?${params.toString()}`, {
        credentials: "include",
      });
      if (!res.ok) throw new Error("Failed to fetch orders");
      return res.json();
    },
  });

  // Fetch users for agent filter
  const { data: users } = useQuery<any[]>({
    queryKey: ["/api/users"],
  });

  // Server returns only Confirmed orders, apply remaining client-side filters
  const confirmedOrders = ordersResponse?.orders || [];

  // Apply client-side filters (search, payment, date)
  const filteredOrders = confirmedOrders.filter((order) => {
    // Search filter
    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      const matchesSearch =
        order.shopifyOrderNumber.toLowerCase().includes(query) ||
        order.customerName.toLowerCase().includes(query) ||
        order.customerPhone.includes(query);
      if (!matchesSearch) return false;
    }

    // Payment method filter
    if (paymentFilter !== "all" && order.paymentMethod !== paymentFilter) {
      return false;
    }

    // Date range filter
    if (dateRange.from && order.confirmedAt) {
      const confirmedDate = new Date(order.confirmedAt);
      if (confirmedDate < dateRange.from) return false;
    }
    if (dateRange.to && order.confirmedAt) {
      const confirmedDate = new Date(order.confirmedAt);
      const toDate = new Date(dateRange.to);
      toDate.setHours(23, 59, 59, 999);
      if (confirmedDate > toDate) return false;
    }

    return true;
  });

  // Server-side pagination - use API's total count for accurate pagination
  const totalOrders = ordersResponse?.total || 0;
  const totalPages = Math.ceil(totalOrders / pageSize);
  // For display, use client-filtered orders from current page
  const paginatedOrders = filteredOrders;
  // Calculate display range for "Showing X-Y of Z orders"
  const startIndex = (currentPage - 1) * pageSize;
  const endIndex = Math.min(startIndex + paginatedOrders.length, totalOrders);

  const agents = users?.filter((u) => u.role === "agent") || [];
  const allSelected = paginatedOrders.length > 0 && selectedOrders.size === paginatedOrders.length;

  const handleSelectAll = () => {
    if (allSelected) {
      setSelectedOrders(new Set());
    } else {
      setSelectedOrders(new Set(paginatedOrders.map((order) => order.id)));
    }
  };

  const handleSelectOrder = (orderId: string) => {
    const newSelected = new Set(selectedOrders);
    if (newSelected.has(orderId)) {
      newSelected.delete(orderId);
    } else {
      newSelected.add(orderId);
    }
    setSelectedOrders(newSelected);
  };

  const handleViewOrder = (order: BackendOrder) => {
    const displayOrder: Order = {
      id: order.id,
      shopifyOrderId: order.shopifyOrderNumber,
      customerName: order.customerName,
      customerPhone: order.customerPhone,
      items: order.itemsSummary || `${order.itemsCount} item(s)`,
      total: Number(order.totalPrice),
      paymentMethod: order.paymentMethod as "cod" | "prepaid",
      status: order.status as "pending" | "assigned" | "confirmed" | "cancelled" | "shipped" | "delivered" | "ndr",
      callStatus: order.callStatus as "Pending" | "Confirmed" | "Cancelled" | "Follow Up" | undefined,
      assignedTo: order.assignedTo || undefined,
      createdAt: new Date(order.createdAt),
    };
    const index = paginatedOrders.findIndex((o) => o.id === order.id);
    setSelectedOrder(displayOrder);
    setSelectedOrderIndex(index);
    setIsQuickPreviewOpen(true);
  };

  const handleNavigateOrder = (direction: "prev" | "next") => {
    const newIndex = direction === "prev" ? selectedOrderIndex - 1 : selectedOrderIndex + 1;
    if (newIndex >= 0 && newIndex < paginatedOrders.length) {
      const order = paginatedOrders[newIndex];
      const displayOrder: Order = {
        id: order.id,
        shopifyOrderId: order.shopifyOrderNumber,
        customerName: order.customerName,
        customerPhone: order.customerPhone,
        items: order.itemsSummary || `${order.itemsCount} item(s)`,
        total: Number(order.totalPrice),
        paymentMethod: order.paymentMethod as "cod" | "prepaid",
        status: order.status as "pending" | "assigned" | "confirmed" | "cancelled" | "shipped" | "delivered" | "ndr",
        callStatus: order.callStatus as "Pending" | "Confirmed" | "Cancelled" | "Follow Up" | undefined,
        assignedTo: order.assignedTo || undefined,
        createdAt: new Date(order.createdAt),
      };
      setSelectedOrder(displayOrder);
      setSelectedOrderIndex(newIndex);
    }
  };

  const getAgentName = (agentId?: string | null) => {
    if (!agentId) return "Unassigned";
    const agent = users?.find((u) => u.id === agentId);
    return agent?.username || agent?.email || "Unknown";
  };

  const handleShipNow = (order: BackendOrder, e: React.MouseEvent) => {
    e.stopPropagation();
    setSelectedOrderForCourier(order);
    setCourierSelectionModalOpen(true);
  };

  const handleClearFilters = () => {
    setSearchQuery("");
    setDateRange({});
    setPaymentFilter("all");
    setAgentFilter("all");
  };

  return (
    <PageLayout
      title="Fulfil"
      description="Confirmed orders ready for fulfillment and shipment"
    >
      <div className="p-6 space-y-6">
        {isLoading ? (
          <div className="space-y-4">
            <Skeleton className="h-16 w-full" data-testid="skeleton-filter" />
            <Skeleton className="h-96 w-full" data-testid="skeleton-table" />
          </div>
        ) : (
          <>
            <FulfilFilter
              searchQuery={searchQuery}
              onSearchChange={setSearchQuery}
              dateRange={dateRange}
              onDateRangeChange={setDateRange}
              agentFilter={agentFilter}
              onAgentFilterChange={setAgentFilter}
              paymentFilter={paymentFilter}
              onPaymentFilterChange={setPaymentFilter}
              agents={agents}
              onClearFilters={handleClearFilters}
            />

            {filteredOrders.length === 0 ? (
              <Card>
                <CardContent className="flex flex-col items-center justify-center py-12">
                  <PackageCheck className="h-12 w-12 text-muted-foreground mb-4" />
                  <p className="text-lg font-medium">No confirmed orders</p>
                  <p className="text-sm text-muted-foreground mt-1">
                    {confirmedOrders.length === 0
                      ? "Confirmed orders will appear here"
                      : "No orders match your filters"}
                  </p>
                </CardContent>
              </Card>
            ) : (
              <div className="flex flex-col gap-4">
                {/* Table Container with Sticky Header and Footer */}
                <div className="rounded-lg border bg-card">
                  <div className="relative">
                    <Table>
                      <TableHeader className="sticky top-0 z-10 bg-card shadow-sm">
                        <TableRow>
                          <TableHead className="w-[50px] bg-card">
                            <Checkbox
                              checked={allSelected}
                              onCheckedChange={handleSelectAll}
                              aria-label="Select all"
                              data-testid="checkbox-select-all"
                            />
                          </TableHead>
                          <TableHead className="w-[120px] bg-card">Order ID</TableHead>
                          <TableHead className="bg-card">Customer</TableHead>
                          <TableHead className="bg-card">Phone</TableHead>
                          <TableHead className="text-right bg-card">Value</TableHead>
                          <TableHead className="bg-card">Payment</TableHead>
                          <TableHead className="bg-card">Confirmed At</TableHead>
                          <TableHead className="bg-card">Agent</TableHead>
                          <TableHead className="text-right bg-card">Actions</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {paginatedOrders.map((order) => (
                          <TableRow
                            key={order.id}
                            className="hover-elevate cursor-pointer"
                            onClick={() => handleViewOrder(order)}
                            data-testid={`row-order-${order.id}`}
                          >
                            <TableCell onClick={(e) => e.stopPropagation()}>
                              <Checkbox
                                checked={selectedOrders.has(order.id)}
                                onCheckedChange={() => handleSelectOrder(order.id)}
                                aria-label={`Select order ${order.shopifyOrderNumber}`}
                                data-testid={`checkbox-order-${order.id}`}
                              />
                            </TableCell>
                            <TableCell className="font-mono text-xs font-medium">
                              #{order.shopifyOrderNumber}
                            </TableCell>
                            <TableCell>
                              <span className="font-medium text-sm">{order.customerName}</span>
                            </TableCell>
                            <TableCell className="font-mono text-xs">
                              {order.customerPhone}
                            </TableCell>
                            <TableCell className="text-right font-medium">
                              ₹{Number(order.totalPrice).toLocaleString("en-IN")}
                            </TableCell>
                            <TableCell>
                              <PaymentBadge method={order.paymentMethod as "cod" | "prepaid"} />
                            </TableCell>
                            <TableCell className="text-sm">
                              {order.confirmedAt ? (
                                format(new Date(order.confirmedAt), "MMM dd, h:mm a")
                              ) : (
                                <span className="text-muted-foreground">-</span>
                              )}
                            </TableCell>
                            <TableCell className="text-sm">
                              {getAgentName(order.assignedTo)}
                            </TableCell>
                            <TableCell className="text-right">
                              <Button
                                size="sm"
                                variant="default"
                                onClick={(e) => handleShipNow(order, e)}
                                data-testid={`button-ship-now-${order.id}`}
                              >
                                <Package className="h-4 w-4 mr-1" />
                                Ship Now
                              </Button>
                            </TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>

                  {/* Pagination Footer */}
                  <div className="sticky bottom-0 bg-card border-t p-4 z-10">
                    <div className="flex items-center justify-between gap-4">
                      <div className="flex items-center gap-2">
                        <span className="text-sm text-muted-foreground">
                          Showing {totalOrders === 0 ? 0 : startIndex + 1}-{endIndex} of {totalOrders} orders
                        </span>
                      </div>

                      <div className="flex items-center gap-4">
                        <div className="flex items-center gap-2">
                          <span className="text-sm text-muted-foreground">Rows per page:</span>
                          <Select value={String(pageSize)} onValueChange={(value) => {
                            setPageSize(Number(value));
                            setCurrentPage(1);
                          }}>
                            <SelectTrigger className="w-[80px]" data-testid="select-page-size">
                              <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                              <SelectItem value="10">10</SelectItem>
                              <SelectItem value="25">25</SelectItem>
                              <SelectItem value="50">50</SelectItem>
                              <SelectItem value="100">100</SelectItem>
                            </SelectContent>
                          </Select>
                        </div>

                        <div className="flex items-center gap-1">
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
                            disabled={currentPage === 1}
                            data-testid="button-prev-page"
                          >
                            <ChevronLeft className="h-4 w-4" />
                            Previous
                          </Button>
                          <span className="text-sm text-muted-foreground px-4">
                            Page {currentPage} of {totalPages || 1}
                          </span>
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
                            disabled={currentPage >= totalPages}
                            data-testid="button-next-page"
                          >
                            Next
                            <ChevronRight className="h-4 w-4" />
                          </Button>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </>
        )}
      </div>

      {/* Order Quick Preview */}
      <OrderQuickPreview
        order={selectedOrder}
        open={isQuickPreviewOpen}
        onOpenChange={setIsQuickPreviewOpen}
        currentIndex={selectedOrderIndex}
        totalOrders={paginatedOrders.length}
        onNavigate={handleNavigateOrder}
      />

      {/* Courier Selection Modal */}
      {selectedOrderForCourier && (
        <CourierSelectionModal
          open={courierSelectionModalOpen}
          onOpenChange={setCourierSelectionModalOpen}
          orderId={selectedOrderForCourier.id}
          orderDetails={{
            shopifyOrderNumber: selectedOrderForCourier.shopifyOrderNumber,
            customerName: selectedOrderForCourier.customerName,
            total: Number(selectedOrderForCourier.totalPrice),
            paymentMethod: selectedOrderForCourier.paymentMethod,
          }}
        />
      )}
    </PageLayout>
  );
}

client/src/components/notifications-bell.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useLocation } from "wouter";
import { Bell } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { formatDistanceToNow } from "date-fns";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";

interface Notification {
  id: string;
  type: string;
  title: string;
  message: string;
  orderId: string | null;
  isRead: boolean;
  readAt: Date | null;
  actionUrl: string | null;
  createdAt: Date;
}

export function NotificationsBell() {
  const { toast } = useToast();
  const [location, setLocation] = useLocation();
  const [open, setOpen] = useState(false);
  const userId = localStorage.getItem("userId");

  // Fetch unread count with proper URL query params
  const { data: unreadCountData } = useQuery<{ count: number }>({
    queryKey: ["/api/notifications/unread-count", userId],
    queryFn: async () => {
      const res = await fetch(`/api/notifications/unread-count?userId=${userId}`, {
        credentials: "include",
      });
      if (!res.ok) throw new Error("Failed to fetch unread count");
      return res.json();
    },
    enabled: !!userId,
    refetchInterval: 30000, // Refetch every 30 seconds
  });

  // Fetch notifications when popover is open with proper URL query params
  const { data: notifications = [], isLoading } = useQuery<Notification[]>({
    queryKey: ["/api/notifications", userId],
    queryFn: async () => {
      const res = await fetch(`/api/notifications?userId=${userId}`, {
        credentials: "include",
      });
      if (!res.ok) throw new Error("Failed to fetch notifications");
      return res.json();
    },
    enabled: open && !!userId,
  });

  // Mark as read mutation
  const markAsReadMutation = useMutation({
    mutationFn: async (notificationId: string) => {
      const res = await apiRequest("PATCH", `/api/notifications/${notificationId}/read`);
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/notifications"] });
      queryClient.invalidateQueries({ queryKey: ["/api/notifications/unread-count"] });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to mark notification as read",
        variant: "destructive",
      });
    },
  });

  // Mark all as read mutation
  const markAllAsReadMutation = useMutation({
    mutationFn: async () => {
      if (!userId) throw new Error("User ID not available");
      const res = await apiRequest("PATCH", "/api/notifications/read-all", { userId });
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/notifications"] });
      queryClient.invalidateQueries({ queryKey: ["/api/notifications/unread-count"] });
      toast({
        title: "Success",
        description: "All notifications marked as read",
      });
    },
    onError: () => {
      toast({
        title: "Error",
        description: "Failed to mark all notifications as read",
        variant: "destructive",
      });
    },
  });

  const unreadCount = unreadCountData?.count || 0;

  const handleNotificationClick = (notification: Notification) => {
    if (!notification.isRead) {
      markAsReadMutation.mutate(notification.id);
    }

    // Close the popover first
    setOpen(false);

    // Handle order-related notifications with smooth sidebar opening
    if (notification.orderId) {
      const isOnOrdersPage = location === "/orders" || location.startsWith("/orders?");

      if (isOnOrdersPage) {
        // Already on orders page - update URL param to trigger sidebar (no reload)
        setLocation(`/orders?selected_order=${notification.orderId}`);
      } else {
        // Navigate to orders page with the order param
        setLocation(`/orders?selected_order=${notification.orderId}`);
      }
    } else if (notification.actionUrl) {
      // Fallback to actionUrl for non-order notifications
      setLocation(notification.actionUrl);
    }
  };

  const handleMarkAllAsRead = () => {
    markAllAsReadMutation.mutate();
  };

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <Button
          variant="ghost"
          size="icon"
          className="relative"
          data-testid="button-notifications"
        >
          <Bell className="h-5 w-5" />
          {unreadCount > 0 && (
            <span className="absolute -top-1 -right-1 h-5 w-5 rounded-full bg-red-600 text-white text-xs flex items-center justify-center font-semibold">
              {unreadCount > 9 ? "9+" : unreadCount}
            </span>
          )}
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-80 p-0" align="end" data-testid="popover-notifications">
        <div className="flex items-center justify-between border-b p-4">
          <h3 className="font-semibold">Notifications</h3>
          {unreadCount > 0 && (
            <Button
              variant="ghost"
              size="sm"
              onClick={handleMarkAllAsRead}
              disabled={markAllAsReadMutation.isPending}
              data-testid="button-mark-all-read"
            >
              Mark all as read
            </Button>
          )}
        </div>

        <ScrollArea className="h-[400px]">
          {isLoading ? (
            <div className="p-4 text-center text-sm text-muted-foreground">
              Loading notifications...
            </div>
          ) : notifications.length === 0 ? (
            <div className="p-8 text-center">
              <Bell className="h-12 w-12 mx-auto mb-3 text-muted-foreground" />
              <p className="text-sm font-medium mb-1">No notifications</p>
              <p className="text-xs text-muted-foreground">
                You're all caught up!
              </p>
            </div>
          ) : (
            <div className="divide-y">
              {notifications.map((notification) => (
                <button
                  key={notification.id}
                  onClick={() => handleNotificationClick(notification)}
                  className={`w-full p-4 text-left hover-elevate transition-colors ${
                    !notification.isRead ? "bg-accent/5" : ""
                  }`}
                  data-testid={`notification-${notification.id}`}
                >
                  <div className="flex items-start gap-3">
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-1">
                        <p className="font-medium text-sm truncate">
                          {notification.title}
                        </p>
                        {!notification.isRead && (
                          <span className="h-2 w-2 rounded-full bg-blue-600 flex-shrink-0" />
                        )}
                      </div>
                      <p className="text-sm text-muted-foreground mb-1 line-clamp-2">
                        {notification.message}
                      </p>
                      <p className="text-xs text-muted-foreground">
                        {formatDistanceToNow(new Date(notification.createdAt), {
                          addSuffix: true,
                        })}
                      </p>
                    </div>
                  </div>
                </button>
              ))}
            </div>
          )}
        </ScrollArea>

        {notifications.length > 0 && (
          <div className="border-t p-2">
            <Button
              variant="ghost"
              size="sm"
              className="w-full"
              onClick={() => setOpen(false)}
              data-testid="button-view-all"
            >
              View all notifications
            </Button>
          </div>
        )}
      </PopoverContent>
    </Popover>
  );
}

server/services/shopifySync.ts.content:
import { storage } from "../storage";
import { updateShopifyClient } from "../shopify";
import type { Order, User } from "@shared/schema";

interface SyncContext {
  userId?: string;
  agentName?: string;
  reason?: string;
  notes?: string;
  followupDate?: Date;
}

export class ShopifySyncService {
  /**
   * Syncs order status changes from our app to Shopify.
   * This is async/non-blocking - errors are logged but don't throw.
   * 
   * @param orderId - Internal order ID
   * @param syncType - Type of sync: 'confirmed', 'cancelled', 'followup'
   * @param context - Additional context data (agent info, notes, etc.)
   */
  async syncToShopify(
    orderId: string,
    syncType: 'confirmed' | 'cancelled' | 'followup',
    context: SyncContext
  ): Promise<void> {
    try {
      // Get order from database
      const order = await storage.getOrder(orderId);
      if (!order) {
        console.error(`[Shopify Sync] Order not found: ${orderId}`);
        return;
      }

      if (!order.shopifyOrderId) {
        console.error(`[Shopify Sync] No Shopify order ID for order: ${orderId}`);
        return;
      }

      // Get user info if userId provided
      let user: User | undefined;
      if (context.userId) {
        user = await storage.getUser(context.userId);
      }

      const agentName = context.agentName || user?.fullName || "Agent";

      console.log(`[Shopify Sync] Starting sync for order ${order.shopifyOrderNumber} (${syncType})`);

      // Update Shopify client with latest credentials
      const client = await updateShopifyClient();

      // Execute sync based on type
      switch (syncType) {
        case 'confirmed':
          await this.syncConfirmed(client, order, agentName, context.notes);
          break;
        case 'cancelled':
          await this.syncCancelled(client, order, agentName, context.reason || 'Other', context.notes);
          break;
        case 'followup':
          await this.syncFollowup(client, order, agentName, context.followupDate, context.notes);
          break;
      }

      // Update order sync status
      await storage.updateOrderSyncStatus(orderId, 'synced', new Date());

      console.log(`[Shopify Sync] ✓ Successfully synced order ${order.shopifyOrderNumber} (${syncType})`);
    } catch (error) {
      console.error(`[Shopify Sync] ✗ Failed to sync order ${orderId}:`, error);

      // Log error to database
      try {
        const order = await storage.getOrder(orderId);
        if (order) {
          await storage.createSyncLog({
            orderId,
            shopifyOrderId: order.shopifyOrderId,
            syncType,
            syncAction: 'batch_update',
            syncStatus: 'failed',
            errorMessage: error instanceof Error ? error.message : String(error),
            retryCount: 0,
          });

          await storage.updateOrderSyncStatus(orderId, 'failed');
        }
      } catch (logError) {
        console.error(`[Shopify Sync] Failed to log sync error:`, logError);
      }
    }
  }

  /**
   * Sync confirmed order status to Shopify
   */
  private async syncConfirmed(
    client: any,
    order: Order,
    agentName: string,
    notes?: string
  ): Promise<void> {
    const shopifyOrderId = order.shopifyOrderId;
    const actions: Promise<any>[] = [];

    // Log start
    const syncLog = await storage.createSyncLog({
      orderId: order.id,
      shopifyOrderId,
      syncType: 'confirmed',
      syncAction: 'add_tag',
      syncStatus: 'pending',
    });

    try {
      // 1. Add OF:confirmed tag
      const existingTags = order.tags || [];
      const newTags = Array.from(new Set([...existingTags, 'OF:confirmed']));
      actions.push(
        client.updateOrderTags(shopifyOrderId, newTags)
          .then(() => console.log(`[Shopify Sync] Added 'OF:confirmed' tag`))
      );

      // 2. Add note with agent and timestamp
      const timestamp = new Date().toLocaleString('en-IN', { 
        timeZone: 'Asia/Kolkata',
        day: '2-digit',
        month: 'short',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
        hour12: false
      });
      const noteText = notes 
        ? `Confirmed by ${agentName} • ${timestamp}\n${notes}`
        : `Confirmed by ${agentName} • ${timestamp}`;

      actions.push(
        client.addOrderNote(shopifyOrderId, noteText)
          .then(() => console.log(`[Shopify Sync] Added verification note`))
      );

      // 3. Set metafield
      actions.push(
        client.updateMetafield(
          shopifyOrderId,
          'verification_status',
          'confirmed',
          'single_line_text_field'
        ).then(() => console.log(`[Shopify Sync] Set verification metafield`))
      );

      actions.push(
        client.updateMetafield(
          shopifyOrderId,
          'verified_by',
          agentName,
          'single_line_text_field'
        ).then(() => console.log(`[Shopify Sync] Set verified_by metafield`))
      );

      actions.push(
        client.updateMetafield(
          shopifyOrderId,
          'verified_at',
          new Date().toISOString(),
          'date_time'
        ).then(() => console.log(`[Shopify Sync] Set verified_at metafield`))
      );

      // Execute all actions in parallel
      await Promise.all(actions);

      // Update sync log
      await storage.updateSyncLog(syncLog.id, {
        syncStatus: 'success',
        syncedAt: new Date(),
      });
    } catch (error) {
      await storage.updateSyncLog(syncLog.id, {
        syncStatus: 'failed',
        errorMessage: error instanceof Error ? error.message : String(error),
      });
      throw error;
    }
  }

  /**
   * Retry helper with exponential backoff
   */
  private async retryWithBackoff<T>(
    fn: () => Promise<T>,
    actionName: string,
    maxRetries: number = 3
  ): Promise<T> {
    let lastError: any;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        console.log(`[Shopify Sync] ${actionName} - Attempt ${attempt}/${maxRetries}`);
        const result = await fn();
        console.log(`[Shopify Sync] ✓ ${actionName} succeeded on attempt ${attempt}`);
        return result;
      } catch (error: any) {
        lastError = error;
        const errorDetails = error instanceof Error ? error.message : JSON.stringify(error);
        console.error(`[Shopify Sync] ✗ ${actionName} failed on attempt ${attempt}:`, errorDetails);

        if (attempt < maxRetries) {
          const backoffMs = Math.pow(2, attempt) * 1000; // 2s, 4s, 8s
          console.log(`[Shopify Sync] Retrying ${actionName} in ${backoffMs}ms...`);
          await new Promise(resolve => setTimeout(resolve, backoffMs));
        }
      }
    }

    throw lastError;
  }

  /**
   * Sync cancelled order status to Shopify
   * NOTE: Order is already cancelled via route handler, this only adds tags/notes
   */
  private async syncCancelled(
    client: any,
    order: Order,
    agentName: string,
    reason: string,
    notes?: string
  ): Promise<void> {
    const shopifyOrderId = order.shopifyOrderId;
    const orderNumber = order.shopifyOrderNumber;

    console.log(`[Shopify Sync] ========================================`);
    console.log(`[Shopify Sync] Starting cancellation sync for order #${orderNumber}`);
    console.log(`[Shopify Sync] Order ID: ${order.id}`);
    console.log(`[Shopify Sync] Shopify Order ID: ${shopifyOrderId}`);
    console.log(`[Shopify Sync] Agent: ${agentName}`);
    console.log(`[Shopify Sync] Reason: ${reason}`);
    console.log(`[Shopify Sync] ========================================`);

    const syncLog = await storage.createSyncLog({
      orderId: order.id,
      shopifyOrderId,
      syncType: 'cancelled',
      syncAction: 'add_tags_notes',
      syncStatus: 'pending',
    });

    let retryCount = 0;
    const errors: string[] = [];

    try {
      // 1. Add OF:cancelled tag with retry
      try {
        const existingTags = order.tags || [];
        const newTags = Array.from(new Set([...existingTags, 'OF:cancelled']));

        console.log(`[Shopify Sync] Current tags:`, existingTags);
        console.log(`[Shopify Sync] New tags to set:`, newTags);

        await this.retryWithBackoff(
          async () => {
            const result = await client.updateOrderTags(shopifyOrderId, newTags);
            console.log(`[Shopify Sync] Tag update response:`, JSON.stringify(result, null, 2));
            return result;
          },
          `Adding 'OF:cancelled' tag to order #${orderNumber}`
        );
      } catch (tagError: any) {
        const errorMsg = `Failed to add tag after 3 retries: ${tagError instanceof Error ? tagError.message : JSON.stringify(tagError)}`;
        console.error(`[Shopify Sync] ✗✗✗ ${errorMsg}`);
        errors.push(errorMsg);
        retryCount++;
      }

      // 2. Add cancellation note with retry
      try {
        const timestamp = new Date().toLocaleString('en-IN', { 
          timeZone: 'Asia/Kolkata',
          day: '2-digit',
          month: 'short',
          year: 'numeric',
          hour: '2-digit',
          minute: '2-digit',
          hour12: false
        });
        const noteText = notes
          ? `Cancelled by ${agentName} • ${timestamp}\nReason: ${reason}\n${notes}`
          : `Cancelled by ${agentName} • ${timestamp}\nReason: ${reason}`;

        console.log(`[Shopify Sync] Note to add:`, noteText);

        await this.retryWithBackoff(
          async () => {
            const result = await client.addOrderNote(shopifyOrderId, noteText);
            console.log(`[Shopify Sync] Note update response:`, JSON.stringify(result, null, 2));
            return result;
          },
          `Adding cancellation note to order #${orderNumber}`
        );
      } catch (noteError: any) {
        const errorMsg = `Failed to add note after 3 retries: ${noteError instanceof Error ? noteError.message : JSON.stringify(noteError)}`;
        console.error(`[Shopify Sync] ✗✗✗ ${errorMsg}`);
        errors.push(errorMsg);
        retryCount++;
      }

      // 3. Set verification_status metafield with retry
      try {
        await this.retryWithBackoff(
          async () => {
            const result = await client.updateMetafield(
              shopifyOrderId,
              'verification_status',
              'cancelled',
              'single_line_text_field'
            );
            console.log(`[Shopify Sync] Verification metafield response:`, JSON.stringify(result, null, 2));
            return result;
          },
          `Setting verification_status metafield for order #${orderNumber}`
        );
      } catch (metaError: any) {
        const errorMsg = `Failed to set verification metafield: ${metaError instanceof Error ? metaError.message : JSON.stringify(metaError)}`;
        console.error(`[Shopify Sync] ✗ ${errorMsg}`);
        errors.push(errorMsg);
      }

      // 4. Set cancellation_reason metafield with retry
      try {
        await this.retryWithBackoff(
          async () => {
            const result = await client.updateMetafield(
              shopifyOrderId,
              'cancellation_reason',
              reason,
              'single_line_text_field'
            );
            console.log(`[Shopify Sync] Cancellation reason metafield response:`, JSON.stringify(result, null, 2));
            return result;
          },
          `Setting cancellation_reason metafield for order #${orderNumber}`
        );
      } catch (metaError: any) {
        const errorMsg = `Failed to set cancellation_reason metafield: ${metaError instanceof Error ? metaError.message : JSON.stringify(metaError)}`;
        console.error(`[Shopify Sync] ✗ ${errorMsg}`);
        errors.push(errorMsg);
      }

      // Determine final status
      if (errors.length === 0) {
        console.log(`[Shopify Sync] ✓✓✓ Sync completed successfully for order #${orderNumber}`);
        await storage.updateSyncLog(syncLog.id, {
          syncStatus: 'success',
          syncedAt: new Date(),
        });
      } else {
        const errorMessage = `Partial sync failure (${errors.length} errors):\n${errors.join('\n')}`;
        console.error(`[Shopify Sync] ✗✗✗ ${errorMessage}`);
        await storage.updateSyncLog(syncLog.id, {
          syncStatus: 'failed',
          errorMessage,
          retryCount,
        });
        throw new Error(errorMessage);
      }

      console.log(`[Shopify Sync] ======================================== END`);
    } catch (error: any) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      console.error(`[Shopify Sync] ✗✗✗ FATAL ERROR during cancellation sync for order #${orderNumber}:`, errorMessage);
      console.error(`[Shopify Sync] Full error object:`, error);

      await storage.updateSyncLog(syncLog.id, {
        syncStatus: 'failed',
        errorMessage,
        retryCount,
      });

      throw error;
    }
  }

  /**
   * Sync follow-up schedule to Shopify
   */
  private async syncFollowup(
    client: any,
    order: Order,
    agentName: string,
    followupDate?: Date,
    notes?: string
  ): Promise<void> {
    const shopifyOrderId = order.shopifyOrderId;
    const actions: Promise<any>[] = [];

    const syncLog = await storage.createSyncLog({
      orderId: order.id,
      shopifyOrderId,
      syncType: 'followup',
      syncAction: 'add_tag',
      syncStatus: 'pending',
    });

    try {
      // 1. Add OF:followup tag
      const existingTags = order.tags || [];
      const newTags = Array.from(new Set([...existingTags, 'OF:followup']));
      actions.push(
        client.updateOrderTags(shopifyOrderId, newTags)
          .then(() => console.log(`[Shopify Sync] Added 'OF:followup' tag`))
      );

      // 2. Add follow-up note
      const followupDateObj = followupDate || order.followupAt || new Date();
      const followupTime = followupDateObj.toLocaleString('en-IN', { 
        timeZone: 'Asia/Kolkata',
        day: '2-digit',
        month: 'short',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
        hour12: false
      });

      const noteText = notes
        ? `Follow-up by ${agentName} • ${followupTime}\n${notes}`
        : `Follow-up by ${agentName} • ${followupTime}`;

      actions.push(
        client.addOrderNote(shopifyOrderId, noteText)
          .then(() => console.log(`[Shopify Sync] Added follow-up note`))
      );

      // 3. Set metafields
      actions.push(
        client.updateMetafield(
          shopifyOrderId,
          'verification_status',
          'followup_scheduled',
          'single_line_text_field'
        ).then(() => console.log(`[Shopify Sync] Set verification metafield`))
      );

      actions.push(
        client.updateMetafield(
          shopifyOrderId,
          'followup_date',
          followupDateObj.toISOString(),
          'date_time'
        ).then(() => console.log(`[Shopify Sync] Set followup_date metafield`))
      );

      // Execute all actions in parallel
      await Promise.all(actions);

      await storage.updateSyncLog(syncLog.id, {
        syncStatus: 'success',
        syncedAt: new Date(),
      });
    } catch (error) {
      await storage.updateSyncLog(syncLog.id, {
        syncStatus: 'failed',
        errorMessage: error instanceof Error ? error.message : String(error),
      });
      throw error;
    }
  }
}

export const shopifySyncService = new ShopifySyncService();

