import { useState, useMemo } from "react";
import { Button } from "@/components/ui/button";
import { Calendar } from "@/components/ui/calendar";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { CalendarIcon } from "lucide-react";
import { format, startOfDay, endOfDay, subDays, startOfMonth, isSameDay } from "date-fns";
import type { DateRange as CalendarDateRange } from "react-day-picker";

type DatePreset = "allTime" | "today" | "yesterday" | "last7days" | "last30days" | "thisMonth" | "custom";

export interface DateRangeOutput {
  startDate: Date | null;
  endDate: Date | null;
}

interface DateRangeSelectorProps {
  dateRange: DateRangeOutput;
  onDateChange: (range: DateRangeOutput) => void;
}

const presets: { key: DatePreset; label: string }[] = [
  { key: "allTime", label: "All Time" },
  { key: "today", label: "Today" },
  { key: "yesterday", label: "Yesterday" },
  { key: "last7days", label: "Last 7 Days" },
  { key: "last30days", label: "Last 30 Days" },
  { key: "thisMonth", label: "This Month" },
];

const getPresetRange = (preset: DatePreset): DateRangeOutput => {
  const now = new Date();
  const today = startOfDay(now);
  const endOfToday = endOfDay(now);

  switch (preset) {
    case "allTime":
      return { startDate: null, endDate: null };
    case "today":
      return { startDate: today, endDate: endOfToday };
    case "yesterday":
      const yesterday = subDays(today, 1);
      return { startDate: yesterday, endDate: endOfDay(yesterday) };
    case "last7days":
      return { startDate: subDays(today, 6), endDate: endOfToday };
    case "last30days":
      return { startDate: subDays(today, 29), endDate: endOfToday };
    case "thisMonth":
      return { startDate: startOfMonth(now), endDate: endOfToday };
    default:
      return { startDate: today, endDate: endOfToday };
  }
};

const detectPresetFromRange = (range: DateRangeOutput | undefined): DatePreset => {
  if (!range?.startDate || !range?.endDate) {
    return "allTime";
  }
  const rangeStart = startOfDay(range.startDate);
  const rangeEnd = startOfDay(range.endDate);

  for (const preset of presets) {
    if (preset.key === "allTime") continue; // Already handled above
    const presetRange = getPresetRange(preset.key);
    if (!presetRange.startDate || !presetRange.endDate) continue;
    const presetStart = startOfDay(presetRange.startDate);
    const presetEnd = startOfDay(presetRange.endDate);

    if (isSameDay(rangeStart, presetStart) && isSameDay(rangeEnd, presetEnd)) {
      return preset.key;
    }
  }
  return "custom";
};

const getPresetLabel = (preset: DatePreset): string | null => {
  const found = presets.find(p => p.key === preset);
  return found ? found.label : null;
};

export function DateRangeSelector({ dateRange, onDateChange }: DateRangeSelectorProps) {
  const [isOpen, setIsOpen] = useState(false);

  // Fallback range for initialization
  const initialRange = dateRange ?? getPresetRange("today");

  // Pending state for draft selection before Apply
  const [pendingRange, setPendingRange] = useState<DateRangeOutput>(() => initialRange);
  const [pendingPreset, setPendingPreset] = useState<DatePreset>(() => detectPresetFromRange(initialRange));
  const [pendingCalendarRange, setPendingCalendarRange] = useState<CalendarDateRange | undefined>(() => 
    initialRange.startDate && initialRange.endDate 
      ? { from: initialRange.startDate, to: initialRange.endDate }
      : undefined
  );

  // Derive display label from dateRange prop using useMemo
  const displayLabel = useMemo(() => {
    const range = dateRange ?? getPresetRange("today");
    const detectedPreset = detectPresetFromRange(range);
    const presetLabel = getPresetLabel(detectedPreset);

    if (presetLabel && detectedPreset !== "custom") {
      return presetLabel;
    }

    const { startDate, endDate } = range;
    if (!startDate || !endDate) {
      return "All Time";
    }
    const startYear = startDate.getFullYear();
    const endYear = endDate.getFullYear();

    if (startYear === endYear) {
      return `${format(startDate, "MMM d")} - ${format(endDate, "MMM d, yyyy")}`;
    }
    return `${format(startDate, "MMM d, yyyy")} - ${format(endDate, "MMM d, yyyy")}`;
  }, [dateRange]);

  const handleOpenChange = (open: boolean) => {
    if (open) {
      // Reset pending state to current committed value (from prop)
      const range = dateRange ?? getPresetRange("today");
      setPendingRange(range);
      setPendingPreset(detectPresetFromRange(range));
      setPendingCalendarRange(
        range.startDate && range.endDate 
          ? { from: range.startDate, to: range.endDate }
          : undefined
      );
    }
    setIsOpen(open);
  };

  const handlePresetClick = (preset: DatePreset) => {
    const range = getPresetRange(preset);
    setPendingPreset(preset);
    setPendingRange(range);
    setPendingCalendarRange(
      range.startDate && range.endDate 
        ? { from: range.startDate, to: range.endDate }
        : undefined
    );
  };

  const handleCalendarSelect = (range: CalendarDateRange | undefined) => {
    setPendingCalendarRange(range);

    if (range?.from && range?.to) {
      const newRange = {
        startDate: startOfDay(range.from),
        endDate: endOfDay(range.to),
      };
      setPendingRange(newRange);
      setPendingPreset(detectPresetFromRange(newRange));
    } else if (range?.from) {
      setPendingPreset("custom");
    }
  };

  const handleApply = (e?: { preventDefault: () => void }) => {
    if (e) e.preventDefault();
    onDateChange(pendingRange);
    setIsOpen(false);
  };

  const handleCancel = (e?: { preventDefault: () => void }) => {
    if (e) e.preventDefault();
    setIsOpen(false);
  };

  return (
    <Popover open={isOpen} onOpenChange={handleOpenChange}>
      <PopoverTrigger asChild>
        <Button
          type="button"
          variant="outline"
          className="justify-start text-left font-normal"
          data-testid="btn-date-range-trigger"
        >
          <CalendarIcon className="mr-2 h-4 w-4" />
          <span>{displayLabel}</span>
        </Button>
      </PopoverTrigger>
      <PopoverContent className="w-auto p-0" align="start">
        <div className="flex flex-col">
          <div className="flex">
            <div className="flex flex-col border-r p-2 space-y-1 min-w-[140px]">
              {presets.map((preset) => (
                <Button
                  key={preset.key}
                  type="button"
                  variant="ghost"
                  size="sm"
                  className={`justify-start toggle-elevate ${
                    pendingPreset === preset.key ? "toggle-elevated bg-accent text-accent-foreground" : ""
                  }`}
                  onClick={() => handlePresetClick(preset.key)}
                  data-testid={`btn-preset-${preset.key}`}
                >
                  {preset.label}
                </Button>
              ))}
            </div>
            <div className="p-2">
              <Calendar
                mode="range"
                selected={pendingCalendarRange}
                onSelect={handleCalendarSelect}
                numberOfMonths={2}
                defaultMonth={subDays(new Date(), 30)}
                data-testid="calendar-date-range"
              />
            </div>
          </div>
          <div className="flex items-center justify-end gap-2 border-t p-2">
            <Button
              type="button"
              variant="ghost"
              size="sm"
              onClick={(e) => handleCancel(e)}
              data-testid="btn-date-cancel"
            >
              Cancel
            </Button>
            <Button
              type="button"
              size="sm"
              onClick={(e) => handleApply(e)}
              disabled={!pendingCalendarRange?.from || !pendingCalendarRange?.to}
              data-testid="btn-date-apply"
            >
              Apply
            </Button>
          </div>
        </div>
      </PopoverContent>
    </Popover>
  );
}

server/logic/rules/delhivery.ts.content:
export interface DelhiveryPayload {
  Shipment: {
    Status: {
      StatusType?: string;
      Status?: string;
      Instructions?: string;
      NSLCode?: string;
    };
    NSLCode?: string;
  };
}

export interface NormalizedStatus {
  status: 'unfulfilled' | 'cancelled' | 'ready_to_ship' | 'in_transit' | 'out_for_delivery' | 'ndr' | 'delivered' | 'rto_initiated' | 'rto_delivered';
  isActionable: boolean;
}

const ACTIONABLE_CODES = [
  "EOD-74",  // Customer Unavailable
  "EOD-15",  // Address Issue
  "EOD-104", // Customer Requested Reschedule
  "EOD-43",  // Customer Not Reachable
  "EOD-86",  // Incomplete Address
  "EOD-11",  // Customer Refused
  "EOD-69",  // COD Amount Not Ready
  "EOD-6",   // Out of Delivery Area
];

export function normalizeDelhivery(payload: DelhiveryPayload): NormalizedStatus {
  // Normalize StatusType to uppercase for consistent matching
  const type = (payload.Shipment?.Status?.StatusType || '').toUpperCase();
  const statusText = payload.Shipment?.Status?.Status || '';
  const instr = (payload.Shipment?.Status?.Instructions || '').toLowerCase();
  const nsl = payload.Shipment?.Status?.NSLCode || payload.Shipment?.NSLCode || '';

  // 1. Handle RTO Delivered (The "DL" Trap)
  if (type === 'DL') {
    if (statusText.toLowerCase().includes('rto') || instr.includes('return')) {
      return { status: 'rto_delivered', isActionable: false };
    }
    return { status: 'delivered', isActionable: false };
  }

  // 2. Handle RTO Initiated
  if (type === 'RT') {
    return { status: 'rto_initiated', isActionable: false };
  }

  // 3. Handle UD (The "Catch-All" Status)
  if (type === 'UD') {
    // A. Check for Out for Delivery (Priority)
    if (instr.includes('out for delivery')) {
      return { status: 'out_for_delivery', isActionable: false };
    }

    // B. Check for Actionable NDR (Strict Whitelist)
    if (ACTIONABLE_CODES.includes(nsl)) {
      return { status: 'ndr', isActionable: true };
    }

    // C. Non-Actionable Failure / Transit Scan
    return { status: 'in_transit', isActionable: false };
  }

  // 4. Default Fallback for other status types (IT, PU, etc.)
  return { status: 'in_transit', isActionable: false };
}

export { ACTIONABLE_CODES };

scripts/test-webhook.ts.content:
/**
 * Test script to verify Delhivery webhook endpoint is working
 * Run with: npx tsx scripts/test-webhook.ts
 */

const BASE_URL = process.env.REPLIT_DEV_DOMAIN 
  ? `https://${process.env.REPLIT_DEV_DOMAIN}` 
  : 'http://localhost:5000';

// Sample Delhivery NDR payload based on their documentation
const sampleNDRPayload = {
  Awb: "TEST-AWB-WEBHOOK",
  ScanCode: "CR", // Customer Refused - an NDR status
  Scan: "Customer Refused",
  Status: "NDR",
  StatusCode: "CR",
  Remarks: "Customer refused to accept delivery - test webhook",
  ScanDateTime: new Date().toISOString(),
  DestinationCity: "DELHI",
  DestinationState: "DELHI",
  ConsigneeName: "Test Customer",
  ConsigneePhone: "9999999999",
  ReferenceNo: "TEST-ORDER-123",
};

async function testWebhook() {
  console.log("=".repeat(60));
  console.log("Testing Delhivery Webhook Endpoint");
  console.log("=".repeat(60));
  console.log(`\nTarget URL: ${BASE_URL}/api/webhooks/delhivery`);
  console.log("\nPayload being sent:");
  console.log(JSON.stringify(sampleNDRPayload, null, 2));
  console.log("\n" + "-".repeat(60));

  try {
    const response = await fetch(`${BASE_URL}/api/webhooks/delhivery`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(sampleNDRPayload),
    });

    const responseText = await response.text();
    let responseBody;
    try {
      responseBody = JSON.parse(responseText);
    } catch {
      responseBody = responseText;
    }

    console.log(`\nResponse Status: ${response.status} ${response.statusText}`);
    console.log("Response Body:");
    console.log(JSON.stringify(responseBody, null, 2));

    if (response.status === 200) {
      console.log("\n✅ SUCCESS: Webhook endpoint received and processed the payload");
      console.log("   Check ndr_events table for new row with AWB: TEST-AWB-WEBHOOK");
    } else if (response.status === 404) {
      console.log("\n⚠️  EXPECTED: 404 - Shipment not found for test AWB");
      console.log("   This is normal for testing. The endpoint is working correctly.");
      console.log("   When Delhivery sends real webhooks with valid AWBs, NDR events will be created.");
    } else {
      console.log("\n❌ UNEXPECTED: Check the response and server logs for details");
    }
  } catch (error: any) {
    console.error("\n❌ ERROR: Failed to reach webhook endpoint");
    console.error("   Error:", error.message);
    console.error("   Make sure the server is running on port 5000");
  }

  console.log("\n" + "=".repeat(60));
}

testWebhook();

client/src/components/hourly-activity-ch.content:
import { useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Skeleton } from "@/components/ui/skeleton";
import { Activity } from "lucide-react";
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Legend,
} from "recharts";
import { startOfDay, endOfDay, format, setHours, setMinutes, setSeconds } from "date-fns";

interface HourlyData {
  hour: string;
  confirmed: number;
  cancelled: number;
  followUp: number;
}

interface HourlyActivityResponse {
  data: HourlyData[];
}

interface HourlyActivityChartProps {
  dateRange: {
    startDate: Date | null;
    endDate: Date | null;
  };
}

export function HourlyActivityChart({ dateRange }: HourlyActivityChartProps) {
  const userId = localStorage.getItem("userId");
  const userRole = localStorage.getItem("userRole");
  const metricsUserId = userRole === "agent" ? userId : undefined;

  // Detect user's browser timezone for accurate hourly grouping
  const userTimezone = Intl.DateTimeFormat().resolvedOptions().timeZone;

  // Default to today if dates are null (All Time selected)
  const effectiveStartDate = dateRange.startDate ?? startOfDay(new Date());
  const effectiveEndDate = dateRange.endDate ?? endOfDay(new Date());

  const { data: hourlyData, isLoading } = useQuery<HourlyActivityResponse>({
    queryKey: ["/api/dashboard/hourly-activity", metricsUserId, effectiveStartDate.toISOString(), effectiveEndDate.toISOString(), userTimezone],
    queryFn: async () => {
      const params = new URLSearchParams();
      if (metricsUserId) params.append("userId", metricsUserId);
      params.append("startDate", effectiveStartDate.toISOString());
      params.append("endDate", effectiveEndDate.toISOString());
      params.append("timezone", userTimezone);

      const res = await fetch(`/api/dashboard/hourly-activity?${params.toString()}`, { credentials: "include" });
      if (!res.ok) throw new Error("Failed to fetch hourly activity");
      return res.json();
    },
    refetchInterval: 60000,
  });

  const chartData = useMemo(() => {
    if (!hourlyData?.data) {
      const formatHour = (h: number): string => {
        if (h === 0) return '12 AM';
        if (h === 12) return '12 PM';
        if (h < 12) return `${h} AM`;
        return `${h - 12} PM`;
      };
      return Array.from({ length: 24 }, (_, i) => ({
        hour: formatHour(i),
        confirmed: 0,
        cancelled: 0,
        followUp: 0,
      }));
    }
    return hourlyData.data;
  }, [hourlyData]);

  const totalActions = useMemo(() => {
    return chartData.reduce(
      (acc, d) => ({
        confirmed: acc.confirmed + d.confirmed,
        cancelled: acc.cancelled + d.cancelled,
        followUp: acc.followUp + d.followUp,
      }),
      { confirmed: 0, cancelled: 0, followUp: 0 }
    );
  }, [chartData]);

  return (
    <Card data-testid="card-hourly-activity">
      <CardHeader className="pb-2">
        <div className="flex items-center justify-between">
          <CardTitle className="flex items-center gap-2 text-sm font-medium">
            <Activity className="h-4 w-4" />
            Hourly Activity
          </CardTitle>
          <div className="flex items-center gap-3 text-xs">
            <div className="flex items-center gap-1">
              <span className="w-2 h-2 rounded-full bg-green-500" />
              <span className="text-muted-foreground">{totalActions.confirmed}</span>
            </div>
            <div className="flex items-center gap-1">
              <span className="w-2 h-2 rounded-full bg-red-500" />
              <span className="text-muted-foreground">{totalActions.cancelled}</span>
            </div>
            <div className="flex items-center gap-1">
              <span className="w-2 h-2 rounded-full bg-blue-500" />
              <span className="text-muted-foreground">{totalActions.followUp}</span>
            </div>
          </div>
        </div>
      </CardHeader>
      <CardContent className="pt-2">
        {isLoading ? (
          <Skeleton className="h-32 w-full" />
        ) : (
          <ResponsiveContainer width="100%" height={140}>
            <AreaChart data={chartData} margin={{ top: 5, right: 5, left: -20, bottom: 5 }}>
              <defs>
                <linearGradient id="colorConfirmed" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#10b981" stopOpacity={0.8} />
                  <stop offset="95%" stopColor="#10b981" stopOpacity={0.1} />
                </linearGradient>
                <linearGradient id="colorCancelled" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#ef4444" stopOpacity={0.8} />
                  <stop offset="95%" stopColor="#ef4444" stopOpacity={0.1} />
